+function resolveLocalFileInput(
+  url: string,
+  mediaKind: "video" | "audio" | null,
+): { filePath: string; mediaType: string; filename: string } | null {
+  try {
+    const parsed = new URL(url);
+    if (parsed.protocol !== "file:") return null;
+    parsed.search = "";
+    parsed.hash = "";
+    const filePath = fileURLToPath(parsed);
+    const filename = basename(filePath);
+    const ext = extname(filename).replace(/^\./, "").toLowerCase();
+    const mediaType =
+      ext === "mp4" || ext === "m4v"
+        ? "video/mp4"
+        : ext === "mov"
+          ? "video/quicktime"
+          : ext === "mkv"
+            ? "video/x-matroska"
+            : ext === "webm"
+              ? mediaKind === "audio"
+                ? "audio/webm"
+                : "video/webm"
+              : ext === "mpeg" || ext === "mpg"
+                ? "video/mpeg"
+                : ext === "avi"
+                  ? "video/x-msvideo"
+                  : ext === "wmv"
+                    ? "video/x-ms-wmv"
+                    : ext === "flv"
+                      ? "video/x-flv"
+                      : ext === "mp3"
+                        ? "audio/mpeg"
+                        : ext === "m4a"
+                          ? "audio/mp4"
+                          : ext === "wav"
+                            ? "audio/wav"
+                            : ext === "flac"
+                              ? "audio/flac"
+                              : ext === "aac"
+                                ? "audio/aac"
+                                : ext === "ogg" || ext === "opus"
+                                  ? "audio/ogg"
+                                  : ext === "aiff"
+                                    ? "audio/aiff"
+                                    : ext === "wma"
+                                      ? "audio/x-ms-wma"
+                                      : mediaKind === "video"
+                                        ? "video/mp4"
+                                        : "audio/mpeg";
+    return { filePath, mediaType, filename };
+  } catch {
+    return null;
+  }
+}
